<template>
  <div id="app">
    <template v-if="host">
      <Navbar class="top" />
      <div class="main" v-bind:class="{hideLeft: !showLeft, showLeft: showLeft}">
        <div class="left">
          <router-view></router-view>
        </div>
        <MainField class="right" />
      </div>
      <Footer class="bottom" />
      <notifications group="main" position="bottom right" />
    </template>
    <div v-else class="container-fluid" style="margin-top: 100px;">
      <div>
        <div class="row">
          <div class="col-12">
            <div class="d-flex justify-content-center">
              <div class="brand">
                <img src="/logo.png" />
                <h1 class="mt-3 mb-5">AutoTouch Dashboard</h1>
              </div>
            </div>
          </div>
        </div>
        <div class="row">
          <div class="col-12 text-center pb-2">
            <p
              class="text-secondary"
            >Turn on Web Server at AutoTouch>Settings, then input the address here.</p>
          </div>
          <div class="col-12">
            <form class="d-flex justify-content-center align-items-baseline">
              <h6 class="text-nowrap">Device Host Address:</h6>
              <input
                type="text"
                v-model="hostInput"
                class="form-control mx-3"
                style="width: 300px;"
                placeholder="192.168.1.123:8080"
              />
              <button class="btn btn-success" @click.stop.prevent="connect">Connect</button>
            </form>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import Navbar from "./components/Navbar.vue";
import FileList from "./components/FileList.vue";
import MainField from "./components/MainField.vue";
import Footer from "./components/Footer.vue";
import VueRouter from "vue-router";
import { mapGetters } from "vuex";

const routes = [{ path: "**", component: FileList }];

const router = new VueRouter({
  routes
});

export default {
  name: "app",
  router,
  components: {
    Navbar,
    MainField,
    Footer
  },
  data() {
    return {
      host: null,
      hostInput: null
    };
  },
  computed: {
    ...mapGetters({
      showLeft: "getShowLeft"
    })
  },
  created() {
    const host = this.$route.query.host;
    if (host) {
      this.updateHost(host);
    }
  },
  methods: {
    updateHost(host) {
      if (host) {
        this.host = host;
        this.$http.defaults.baseURL = host.startsWith("http")
          ? host
          : `http://${host}`;

        this.$router.replace({ query: { host } }).catch(() => {});
      }
    },
    connect() {
      this.updateHost(this.hostInput);
    }
  }
};
</script>
