                        clip-rule="evenodd"
                      />
                    </svg>
                  </template>
                  <b-dropdown-item v-on:click.stop.prevent="deleteFile(file.filePath)">Delete</b-dropdown-item>
                  <b-dropdown-item v-on:click.stop.prevent="renameFile(file.filePath)">Rename</b-dropdown-item>
                </b-dropdown>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

    <b-modal id="modal-upload-file" ref="modal-upload-file" title="Upload File" hide-footer>
      <form
        enctype="multipart/form-data"
        method="post"
        id="uploadForm"
        class="d-flex justify-content-between"
      >
        <input id="file" name="file" type="file" />
        <input
          type="submit"
          value="Upload"
          id="uploadSubmit"
          v-on:click.stop.prevent="uploadFile()"
        />
      </form>
    </b-modal>
  </div>
</template>

<script>
let common = require("../common");
import Breadcrumb from "./Breadcrumb.vue";

export default {
  name: "FileList",
  components: {
    Breadcrumb
  },
  data() {
    return {
      files: [],
      currentPath: "/",
      runningScripts: [],
      refreshIntervalId: null
    };
  },
  created() {
    this.currentPath = this.$route.path;
    this.$store.commit("setCurrentDir", this.currentPath);
    this.loadFiles();
    this.refreshIntervalId = setInterval(() => {
      this.getRunningScripts();
    }, 3000);
  },
  beforeRouteUpdate(to, from, next) {
    next();
    this.currentPath = this.$route.path;
    this.$store.commit("setCurrentDir", this.currentPath);
    this.loadFiles();
  },
  destroyed() {
    clearInterval(this.refreshIntervalId);
  },
  methods: {
    clickOnFile(file) {
      this.$store.commit("setShowLog", false);
      const fileType = common.getFileType(file.filePath);
      if (
        fileType === "js" ||
        fileType === "lua" ||
        fileType === "txt" ||
        fileType === "img"
      ) {
        this.getFileContent(file.filePath);
      }
    },
    hasFiles() {
      return this.files && this.files.length > 0;
    },
    loadFiles() {
      let self = this;

      //   var files = require("../test-data.json");
      //   self.files = files.files;
      //   return;

      var filePath = this.currentPath;
      var url = "/files?path=" + encodeURIComponent(filePath);
      self.$http
        .get(url)
        .then(function(response) {
          self.files = response.data.files;
          self.$notify({
            group: "main",
            type: "success",
            text: "Files reloaded!"
          });
        })
        .catch(function(error) {
          self.$notify({ group: "main", type: "error", text: error });
        });
    },
    getRunningScripts() {
      let self = this;

      var url = "/runningScripts";
      self.$http
        .get(url)
        .then(function(response) {
          self.runningScripts = response.data;
        })
        .catch(function(error) {
          // handle error
          console.log(error);
        });
    },
    fileName(file) {
      var fileName = common.getFilename(file.filePath);
      return fileName;
    },
    fileNameLink(file) {
      var filePath = file.filePath;
      var iconName = file.iconName;

      var link;
      if (common.isFolder(iconName)) {
        link = "/?path=" + encodeURIComponent(filePath);
      } else if (common.isImage(iconName)) {
        link = "/file/view?path=" + encodeURIComponent(filePath);
      } else {
        link = "/file/edit?path=" + encodeURIComponent(filePath);
      }
      return link;
    },
    play(filePath) {
      const self = this;
      var url = "/control/start_playing?path=" + encodeURIComponent(filePath);
      self.$http
        .get(url)
        .then(function(response) {
          var respObj = response.data;
          if (respObj.status != "success") {
            self.$notify({
              group: "main",
              type: "error",
              text: respObj.info
            });
          }
        })
        .catch(function(error) {
          self.$notify({ group: "main", type: "error", text: error });
        });
    },
    stop(filePath) {
      const self = this;
      var url = "/control/stop_playing?path=" + encodeURIComponent(filePath);
      self.$http
        .get(url)
        .then(function(response) {
          var respObj = response.data;
          if (respObj.status != "success") {
            self.$notify({
              group: "main",
              type: "error",
              text: respObj.info
            });
          }
        })
        .catch(function(error) {
          self.$notify({ group: "main", type: "error", text: error });
        });
    },
    renameFile(oldFilePath) {
      let self = this;

      var newFilename = prompt("Please input the new filename", "");
      if (newFilename) {
        var newFilePath = self.currentPath + "/" + newFilename;
        askServerToRenameFile(oldFilePath, newFilePath);
      }

      function askServerToRenameFile(oldFilePath, newFilePath) {
        var url =
          "/file/rename?path=" +
          encodeURIComponent(oldFilePath) +
          "&newPath=" +
          encodeURIComponent(newFilePath);

        self.$http
          .get(url)
          .then(function(response) {
            var respObj = response.data;
            if (respObj.status == "success") {
              self.loadFiles();
            } else {
              self.$notify({
                group: "main",
                type: "error",
                text: respObj.info
              });
            }
          })
          .catch(function(error) {
            self.$notify({ group: "main", type: "error", text: error });
          });
      }
    },
    deleteFile(filePath) {
      let self = this;
      if (confirm("Are you sure to delete the file?")) {
        var url = "/file/delete?path=" + encodeURIComponent(filePath);
        self.$http
          .get(url)
          .then(function(response) {
            var respObj = response.data;
            if (respObj.status == "success") {
              self.loadFiles();
            } else {
              self.$notify({
                group: "main",
                type: "error",
                text: respObj.info
              });
            }
          })
          .catch(function(error) {
            self.$notify({ group: "main", type: "error", text: error });
          });
      }
    },
    isFolder(iconName) {
      return common.isFolder(iconName);
    },
    isLuaPackage(filePath) {
      return common.isLuaPackage(filePath);
    },
    isScript(filePath) {
      return common.isScript(filePath);
    },
    isRunning(filePath) {
      return this.runningScripts.includes(filePath);
    },
    newFile() {
      let self = this;

      var filename = prompt("Please input the filename", "");
      if (filename) {
        if (
          !filename.toLowerCase().endsWith(".txt") &&
          !filename.toLowerCase().endsWith(".lua") &&
          !filename.toLowerCase().endsWith(".js")
        ) {
          filename = filename + ".js";
        }
        var newFilePath = self.currentPath + "/" + filename;
        askServerToNewFile(newFilePath);
      }

      function askServerToNewFile(filePath) {
        var url = "/file/new?path=" + encodeURIComponent(filePath);
        self.$http
          .get(url)
          .then(function(response) {
            var respObj = response.data;
            if (respObj.status == "success") {
              self.loadFiles();
            } else {
              self.$notify({
                group: "main",
                type: "error",
                text: respObj.info
              });
            }
          })
          .catch(function(error) {
            self.$notify({ group: "main", type: "error", text: error });
          });
      }
    },
    newFolder() {
      let self = this;

      var filename = prompt("Please input the folder name", "");
      if (filename) {
        var newFilePath = self.currentPath + "/" + filename;
        askServerToNewFile(newFilePath);
      }

      function askServerToNewFile(filePath) {
        var url = "/file/newFolder?path=" + encodeURIComponent(filePath);
        self.$http
          .get(url)
          .then(function(response) {
            var respObj = response.data;
            if (respObj.status == "success") {
              self.loadFiles();
            } else {
              self.$notify({
                group: "main",
                type: "error",
                text: respObj.info
              });
            }
          })
          .catch(function(error) {
            self.$notify({ group: "main", type: "error", text: error });
          });
      }
    },
    uploadFile() {
      const self = this;
      var file = document.getElementById("file").files[0];
      if (file) {
        var filePath = this.currentPath + "/" + file.name;
        var action = "/file/upload?path=" + encodeURIComponent(filePath);

        var formData = new FormData();
        formData.append("file", file);
        self.$http
          .post(action, formData, {
            headers: {
              "Content-Type": "multipart/form-data"
            }
          })
          .then(function(response) {
            var respObj = response.data;
            if (respObj.status == "success") {
              self.loadFiles();
              self.$refs["modal-upload-file"].hide();
              self.$notify({
                group: "main",
                type: "success",
                text: "Uploaded successfully!"
              });
            } else {
              self.$notify({
                group: "main",
                type: "error",
                text: respObj.info
              });
            }
          })
          .catch(function(error) {
            self.$notify({ group: "main", type: "error", text: error });
          });
      }
    },
    getFileContent(filePath) {
      let self = this;

      self.$store.commit("setShowLoading", true);

      var url = "/file/content?path=" + encodeURIComponent(filePath);
      self.$http
        .get(url)
        .then(function(response) {
          var respObj = response.data;
          if (respObj.status === "success") {
            const content = respObj.content;
            self.$store.commit("setCurrentFile", {
              filePath,
              content
            });
          } else {
            self.$notify({
              group: "main",
              type: "error",
              text: respObj.info
            });
          }
        })
        .catch(function(error) {
          self.$notify({ group: "main", type: "error", text: error });
        })
        .finally(function() {
          self.$store.commit("setShowLoading", false);
        });
    }
  }
};
</script>
